import React, { useEffect, useState } from 'react';
import './Sidebar.css';
import axios from 'axios';

const Sidebar = ({ onSelectionChange, selectedCategory }) => {
    const [categories, setCategories] = useState([]);

    useEffect(() => {
        // Haal categories van backend
        const fetchCategories = async () => {
            try {
                const res = await axios.get('http://localhost:3007/api/categories', { withCredentials: true });
                setCategories(res.data);
            } catch (err) {
                console.error('Kon categories niet laden', err);
            }
        };
        fetchCategories();
    }, []);

    return (
        <nav className="sidebar">
            <div className="sidebar-header">Filters</div>
            <ul className="sidebar-list">
                <li className={`sidebar-list-item ${selectedCategory === null ? 'active' : ''}`}
                    onClick={() => onSelectionChange(null)}>
                    All Categories
                </li>
                {categories.map(cat => (
                    <li
                        key={cat.id_category}
                        className={`sidebar-list-item ${selectedCategory === String(cat.id_category) ? 'active' : ''}`}
                        onClick={() => onSelectionChange(String(cat.id_category))}
                    >
                        {cat.category_name}
                    </li>
                ))}
            </ul>
            <div className="sidebar-footer">Select category to filter</div>
        </nav>
    );
};

export default Sidebar;
